prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?taskName WHERE {
  ?task a bboExt:ChoreographyTask .
  ?task tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_bce75566_36a6_4093_94c7_b431843dafc9> .
  OPTIONAL { ?task bbo:name ?taskName . }
  FILTER NOT EXISTS {
    <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-991D05FE-26B7-4205-BF51-AE58231837BA>
      ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
  }
}
